80	    unsigned               in_progress:1;
81	
82	    /*
83	     * Body-read ownership state for the js_access phase handler.
84	     *
85	     * readRequest*() cannot call ngx_http_read_client_request_body()
86	     * from the JS native directly.  The phase handler must choose between
87	     * NGX_AGAIN ("I still own the request") and NGX_DONE ("I finalized
88	     * it myself"), but which one is correct depends on whether the body
89	     * read completes synchronously or goes async -- and that is only
90	     * known after the call returns.
91	     *
92	     * In the async case the body reader takes over r->read_event_handler
93	     * and may call ngx_http_finalize_request() on I/O errors without
94	     * invoking our post_handler.  If the phase handler had returned
95	     * NGX_AGAIN, both the phase engine and the body reader would own
96	     * the request, causing a hang on errors such as chunked 413.
97	     *
98	     *   IDLE         no body read requested (initial and terminal state).
99	     *   DEFERRED     JS called readRequest*(); the access handler
100	     *                will start the read after engine->call() returns.
101	     *   IN_PROGRESS  ngx_http_read_client_request_body() returned
102	     *                NGX_AGAIN; request ownership transferred to the
103	     *                body reader via NGX_DONE.  access_body_done
104	     *                callback resumes phases on completion.
105	     *
106	     * IDLE -> DEFERRED -> IDLE                  (sync completion or error)
107	     * IDLE -> DEFERRED -> IN_PROGRESS -> IDLE   (async completion)
108	     */
109	#define NGX_HTTP_JS_BODY_READ_IDLE 0
110	#define NGX_HTTP_JS_BODY_READ_DEFERRED 1
111	#define NGX_HTTP_JS_BODY_READ_IN_PROGRESS 2
112	#define NGX_HTTP_JS_BODY_READ_FORM 4
113	#define ngx_http_js_body_read_phase(state) ((state) & 3)
114	#define ngx_http_js_body_read_is_form(state)                                  \
115	    (((state) & NGX_HTTP_JS_BODY_READ_FORM) != 0)
116	#define ngx_http_js_body_read_is_deferred(state)                              \
117	    (ngx_http_js_body_read_phase(state) == NGX_HTTP_JS_BODY_READ_DEFERRED)
118	#define ngx_http_js_body_read_is_in_progress(state)                           \
119	    (ngx_http_js_body_read_phase(state) == NGX_HTTP_JS_BODY_READ_IN_PROGRESS)
120	#define ngx_http_js_body_read_to_in_progress(state)                           \
121	    (((state) & NGX_HTTP_JS_BODY_READ_FORM)                                   \
122	     | NGX_HTTP_JS_BODY_READ_IN_PROGRESS)
123	    unsigned               body_read_state:3;
124	
125	    /*
126	     * Collected request body as a contiguous buffer.
127	     * Shared by both synchronous property getters (requestText,
128	     * requestBuffer) and async readRequest*() methods.
129	     */
130	    unsigned               body_read_nul:1;
131	    u_char                *body_read_data;
132	    size_t                 body_read_len;
133	
134	    /* Pending promise/event for deferred body reads. */
135	    void                  *body_read_event;
136	
137	    ngx_js_form_t         *request_form;
138	};
